source.@value:
rule "Windows - Applocker - Enrichment 52"
when
    has_field("source")
then
    let team = lookup_value(
        lookup_table: "my-servermanagementlist", 
        key: to_string($message.source)
    );
    set_field (
        field: "appteam",
        value: "UNDEFINED"
    );
    set_field (
        field: "appteam", 
        value: team
    ); 

end

rule "Windows - Applocker - NXLog - Normalization 21"

when
    to_string($message.SourceName) == "Microsoft-Windows-AppLocker"

then
    rename_field(
        "Domain", 
        "TargetDomainName"
    );
    rename_field(
        "EventID",
        "event_code"
    );
    rename_field(
        "AccountName", 
        "user_name"
    );
    rename_field(
        "AccountType", 
        "user_type"
    );
    rename_field(
        "UserID", 
        "user_id"
    );

    set_field(
        field: "source",
        value: to_string($message.collector_node_id)
    );

end

rule "Windows - AppLocker - Parsing 33" 

when 
    to_string($message.SourceName) == "Microsoft-Windows-AppLocker" AND 
    ( 
        to_long($message.event_code) >= 8020 AND 
        to_long($message.event_code) <= 8025 
    )

then
    let applocker = grok( 
        pattern: "%{WORD:appbase}[A-Z.]+%{WORD:appname} %{GREEDYDATA}", 
        value: uppercase(to_string($message.message)), only_named_captures: true 
    ); 

    let apppath = grok( 
        pattern: "%{GREEDYDATA:apppath}[.]%{WORD} %{GREEDYDATA}", 
        value: uppercase(to_string($message.message)), only_named_captures: true 
    ); 

    set_field("appextension", "APP");
    set_fields(apppath);
    set_fields(applocker); 

end

rule "Windows - Applocker - Enrichment 51"

when 
    to_string($message.SourceName) == "Microsoft-Windows-AppLocker" AND
    (
        to_long($message.event_code) >= 8002 AND
        to_long($message.event_code) <= 8007
    ) OR
    ( 
        to_long($message.event_code) >= 8020 AND 
        to_long($message.event_code) <= 8025 
    )

then 
    let appcat = lookup_value(
        lookup_table: "my-applicationwhitelist", 
        key: to_string($message.appid)
    );
    set_field (
        field: "appcat", 
        value: "UNDEFINED"
    );
    set_field (
        field: "appcat", 
        value: appcat
    ); 

end

rule "Windows - Applocker - Winlogbeat - Normalization 22"

when
    to_string($message.winlogbeat_event_provider) == "Microsoft-Windows-AppLocker"

then
    rename_field(
        "winlogbeat_winlog_user_domain", 
        "TargetDomainName"
    );
    rename_field(
        "winlogbeat_event_code",
        "event_code"
    );
    rename_field(
        "winlogbeat_winlog_event_id",
        "event_code"
    );
    rename_field(
        "winlogbeat_winlog_user_name", 
        "user_name"
    );
    rename_field(
        "winlogbeat_winlog_user_type", 
        "user_type"
    );
    rename_field(
        "winlogbeat_winlog_user_identifier", 
        "user_id"
    );
    set_field(
        field: "SourceName",
        value: to_string($message.winlogbeat_event_provider)
    );

end

rule "Windows - AppLocker - Parsing 34" 

when 
    to_string($message.SourceName) == "Microsoft-Windows-AppLocker" AND 
    ( 
        to_long($message.event_code) >= 8002 AND 
        to_long($message.event_code) <= 8007 
    ) 

then 
    let app = regex( 
        pattern: "(([\\%]*)([A-Z0-9]+|[A-Z]:\\\\)([\\%]*)([\\\\\\sa-zA-Z0-9\\$_.-]*\\\\)+([\\sa-zA-Z0-9\\$_.-]+).([A-Z0-9]{3,6}))", 
        value: to_string($message.message) 
    ); 

    let appname = regex( 
        pattern:"(\\\\APPDATA\\\\LOCAL\\\\TEMP\\\\)", 
        value: to_string($message.message) 
    ); 

    set_field("apppath",app["0"]);
    set_field("appbase",app["2"]);
    set_field("appname",app["5"]);
    set_field("appextension",app["6"]);

    set_field("appname", replace(to_string(appname["0"]), to_string(appname["0"]),"SYSTEMTOOL")); 

end
